    for (int i = lines.size() - 1; i >= 0; i--) {
        String line = lines.get(i);
        if (line.length() > 0) {
            return parseDir(line, path);
        }
    }
    // all lines are blank
    throw new IOException(
            "Command line 'dir /-c' did not return any info " +
            "for path '" + path + "'");
